    String funcionActual = "";
    String tipoRetornoActual = "";
    boolean retornoEncontrado = false;
    boolean codigoInalcanzableActivo = false;

    boolean tiposCompatibles(String esperado, String recibido) {
        if (esperado == null || recibido == null) return false;

        if (esperado.equals(recibido)) return true;

        // Permitir int -> float
        if (esperado.equals("float") && recibido.equals("int")) return true;

        return false;
    }
    int contextoBreak = 0;

    void validarBreak(int linea, int columna) {
        if (contextoBreak <= 0) {
            ErroresSemanticos.agregar(
                "Error semántico en línea " + linea +
                ", columna " + columna +
                ": 'break' solo puede usarse dentro de un ciclo o switch."
            );
        }
    }

    void validarCodigoInalcanzable(int linea, int columna) {
        if (codigoInalcanzableActivo) {
            ErroresSemanticos.agregar(
                "Error semántico en línea " + linea +
                ", columna " + columna +
                ": código inalcanzable después de return."
            );
        }
    }

